const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const chunk_id = body.chunk_id || null;
if (!chunk_id) return { json: { _error: true, error: 'chunk_id required', ok: false } };
return { json: { chunk_id, _t0: Date.now() } };

const arr = $input.item.json || [];
const chunk = Array.isArray(arr) && arr.length > 0 ? arr[0] : null;
const parsed = $('Parse Input').first().json;
if (!chunk) return { json: { _skip: true, reason: 'chunk not found', chunk_id: parsed.chunk_id } };
const system_prompt = 'Crystallux real-time transcript classifier. Output STRICT JSON: { intent, sentiment, sentiment_score, topics }. intent ∈ {discovery_question, objection, closing_signal, stall, confusion, buy_signal, dismissal, small_talk, information_share}. sentiment ∈ {positive, neutral, negative, mixed}. sentiment_score ∈ [-1.0, 1.0]. topics: array of 0-3 short nouns. No prose.';
const user_prompt = 'Speaker: ' + chunk.speaker + '\nText: ' + chunk.transcript_text;
return { json: Object.assign({}, parsed, { chunk, system_prompt, user_prompt }) };

const resp = $input.item.json || {};
const prep = $('Build Payload').first().json;
const t0 = prep._t0 || Date.now();
const latency = Date.now() - t0;
let parsed = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  if (text.trim().length > 0) parsed = JSON.parse(text.trim());
} catch (e) { parsed = null; }

const allowedIntents = ['discovery_question','objection','closing_signal','stall','confusion','buy_signal','dismissal','small_talk','information_share'];
const allowedSentiments = ['positive','neutral','negative','mixed'];

const intent = parsed && allowedIntents.indexOf(parsed.intent) !== -1 ? parsed.intent : 'unknown';
const sentiment = parsed && allowedSentiments.indexOf(parsed.sentiment) !== -1 ? parsed.sentiment : 'unknown';
const sentiment_score = parsed && typeof parsed.sentiment_score === 'number' ? Math.max(-1, Math.min(1, parsed.sentiment_score)) : null;
const topics = parsed && Array.isArray(parsed.topics) ? parsed.topics.slice(0, 3) : [];

return { json: {
  chunk_id: prep.chunk_id,
  call_id: prep.chunk.call_id,
  client_id: prep.chunk.client_id,
  agent_id: prep.chunk.agent_id,
  intent, sentiment, sentiment_score, topics,
  latency_ms: latency,
  latency_high: latency > 3000
} };
